  ('zeitverzoegertes-vitamin-c', 'Enhanced Vitamin C Delivery SLR 2025', '39861409', 'Systematic Literature Review', '1a', '-', 'Alternative Vitamin-C-Formen vs. Ascorbinsäure', '-', '⚠️ ''Studies on sustained-release vitamin C were all against placebo, disabling any conclusion on benefits over ascorbic acid.''', 'Unklar', '-', 'Keine Evidenz für Überlegenheit über Standard-Ascorbinsäure! Mehr Forschung nötig.'),
  ('vitamin-d2', 'Tripkovic 2012 Meta-Analyse', '22552031', 'Meta-Analyse', '1a', '~1000 (7 RCTs)', 'D2 vs D3 Serumspiegelerhoeung', 'Variabel (300-50000 IE)', 'D3 erhoeht 25(OH)D um 15,23 nmol/L mehr als D2 (P=0,001). Bei Bolus: P=0,0002. Bei taeglicher Gabe: P=0,10 (NICHT signifikant!).', 'Stark (Bolus) / Gering (taeglich)', 'Keine spezifischen', '⚠️ KERNAUSSAGE: Bei taeglicher Niedrigdosis sind D2 und D3 annaehernd gleichwertig! Nur bei Bolus-Gaben ist D3 deutlich ueberlegen.'),
  ('vitamin-d2', 'Heaney 2011', '21177785', 'RCT', '1b', '33', 'D2 vs D3 Potenz', '50.000 IE/Woche x 12 Wochen', 'D3 ist 87% wirksamer als D2 bei woechentlicher Gabe. D3 Potenz/D2 Potenz = 9,5:1 (Einzeldosis) bis 1,87:1 (Wochen-Gabe).', 'Stark', 'Keine schweren', 'Bei woechentlicher/monatlicher Dosierung: D3 stark bevorzugen. D2 nur wenn vegan zwingend.'),
  ('vitamin-d2', 'Armas 2004', '15531486', 'RCT', '1b', '20', 'D2 vs D3 Einzeldosis', '50.000 IE Einzeldosis', 'AUC: D3 = 204,7 ng·d/mL, D2 = 60,2 ng·d/mL. Faktor 9,5 zugunsten D3!', 'Sehr stark', 'Keine', 'Bei Einmaldosis (Stosstherapie): D3 MASSIV wirksamer. D2 fuer Stosstherapie NICHT empfehlen.'),
  ('vitamin-d2', 'Bjelakovic 2014 Cochrane', '24414552', 'Meta-Analyse (Cochrane)', '1a', '>50.000 (56 RCTs)', 'Mortalitaet', 'Variabel', '⚠️ KRITISCH: D3 reduziert Gesamtmortalitaet signifikant (RR 0,94; 95% CI 0,91-0,98). D2 zeigt KEINEN Effekt auf Mortalitaet (RR 1,02)!', 'D3: Moderat / D2: Kein Effekt', 'Keine spezifischen', '⚠️ WICHTIG: D2 hat KEINEN nachgewiesenen Effekt auf Sterblichkeit. D3 bevorzugen wenn moeglich!'),
  ('vitamin-d2', 'Tripkovic 2017', '28679555', 'RCT', '1b', '335', 'D2 vs D3 Wintermonate', '600 IE/Tag (15 mcg) x 12 Wochen', 'D3 erhoehte 25(OH)D doppelt so effektiv wie D2 bei taeglicher 600 IE Gabe. Aber: Beide Formen verhinderten Winterabfall.', 'Moderat', 'Keine', 'Auch bei Niedrigdosis war D3 wirksamer. Aber D2 verhinderte erfolgreich den saisonalen D-Abfall.'),
  ('vitamin-d2', 'Holick 2008', '18089691', 'RCT', '1b', '68', 'D2 vs D3 Aequivalenz', '1.000 IE/Tag x 11 Wochen', 'Bei taeglicher 1000 IE Gabe: D2 und D3 GLEICHWERTIG in Serumspiegelerhoeung.', 'Neutral', 'Keine', 'Holick-Studie zeigt: Bei taeglicher Niedrigdosis koennen beide Formen als gleichwertig betrachtet werden.'),
  ('vitamin-d3', 'Bjelakovic 2014 Cochrane - Mortalitaet', '24414552', 'Meta-Analyse (Cochrane)', '1a', '95286 (56 RCTs)', 'Gesamtmortalitaet', 'Variabel', '⚠️ KRITISCH: D3 reduziert Mortalitaet signifikant: RR 0,94 (95% CI 0,91-0,98). D2: RR 1,02 (KEIN Effekt!). Krebsmortalitaet: RR 0,88.', 'Moderat', 'Keine spezifischen', '⚠️ WICHTIGSTE STUDIE: D3 reduziert Sterblichkeit, D2 NICHT! D3 als Standard empfehlen.'),
  ('vitamin-d3', 'Frakturen D+Ca Meta-Analyse 2019', '31860103', 'Meta-Analyse (Cochrane)', '1a', '>50.000', 'Frakturen', 'Variabel', 'D allein: RR 1,00 - KEIN EFFEKT! D+Calcium: RR 0,94 (6% Reduktion). Hueftfraktur D+Ca: RR 0,84 (16% Reduktion).', 'Moderat (D+Ca) / Kein Effekt (D allein)', 'Keine', '⚠️ D allein reduziert Frakturen NICHT! Immer mit CALCIUM kombinieren fuer Knochengesundheit.'),
